"""matplotlib.contour — contour plot classes."""

from matplotlib.artist import Artist
import numpy as _np


class ContourSet(Artist):
    def __init__(self, ax, *args, **kwargs):
        super().__init__()
        self.ax = ax
        self.levels = kwargs.get('levels', [])
        self.collections = []
        self.allsegs = []
        self.allkinds = []
        self.cvalues = []

    def clabel(self, levels=None, **kwargs):
        return []

    def changed(self): pass
    def get_array(self): return _np.array(self.cvalues)
    def set_array(self, A): pass


class QuadContourSet(ContourSet):
    pass


class ClabelText:
    pass
